const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});

let i = 0;
let t;
let input = [];
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
    } else {
        input.push(parseInt(line));
    }
    i++;
    if (i > t) {
        readline.close();
        main();
    }
});

